INSERT INTO posts (id, content, locale, translation_of, created_at) VALUES
('00bbbb0000000001', 'You mostly dislike criticism because it was phrased badly, not because it was false.', 'en', NULL, '2024-08-03 09:15:00'),
('00cccc0000000001', 'No te molesta la crítica porque sea falsa, sino porque a menudo llega mal dicho.', 'es', '00bbbb0000000001', '2024-08-03 09:15:00'),
('00bbbb0000000002', 'The version of you that exists in other people’s heads is not under your control.', 'en', NULL, '2024-08-09 16:51:36'),
('00cccc0000000002', 'La versión de ti que vive en la cabeza de los demás no la controlas tú.', 'es', '00bbbb0000000002', '2024-08-09 16:51:36'),
('00bbbb0000000003', 'You do not miss them; you miss who you were when you felt chosen.', 'en', NULL, '2024-08-16 00:28:13'),
('00cccc0000000003', 'No les echas de menos a ellos; echas de menos a la persona que eras cuando te sentías elegido.', 'es', '00bbbb0000000003', '2024-08-16 00:28:13'),
('00bbbb0000000004', 'Polite silence is often agreement with something you claim to oppose.', 'en', NULL, '2024-08-22 08:04:50'),
('00cccc0000000004', 'El silencio educado suele ser conformidad con lo que dices rechazar.', 'es', '00bbbb0000000004', '2024-08-22 08:04:50'),
('00bbbb0000000005', 'You rehearse generosity in your head more often than you practice it with your wallet.', 'en', NULL, '2024-08-28 15:41:27'),
('00cccc0000000005', 'Ensayas la generosidad en la cabeza más de lo que la practicas con el bolsillo.', 'es', '00bbbb0000000005', '2024-08-28 15:41:27'),
('00bbbb0000000006', 'Most “authentic” brands are focus-grouped sincerity.', 'en', NULL, '2024-09-03 23:18:04'),
('00cccc0000000006', 'La mayoría de marcas “auténticas” son sinceridad pasada por grupo focal.', 'es', '00bbbb0000000006', '2024-09-03 23:18:04'),
('00bbbb0000000007', 'You judge strangers by seconds and demand years to judge yourself.', 'en', NULL, '2024-09-10 06:54:41'),
('00cccc0000000007', 'Juzgas a un desconocido en segundos y te pides años para juzgarte a ti.', 'es', '00bbbb0000000007', '2024-09-10 06:54:41'),
('00bbbb0000000008', 'The cruelest thing you can do to someone is make them feel ordinary when they thought they were special.', 'en', NULL, '2024-09-16 14:31:18'),
('00cccc0000000008', 'Lo más cruel es hacer sentir a alguien ordinario cuando creía ser especial.', 'es', '00bbbb0000000008', '2024-09-16 14:31:18'),
('00bbbb0000000009', 'You confuse being busy with being important.', 'en', NULL, '2024-09-22 22:07:55'),
('00cccc0000000009', 'Confundes estar ocupado con ser importante.', 'es', '00bbbb0000000009', '2024-09-22 22:07:55'),
('00bbbb000000000a', 'Forgiveness is sometimes just exhaustion wearing a spiritual outfit.', 'en', NULL, '2024-09-29 05:44:32'),
('00cccc000000000a', 'Perdonar a veces es solo el cansancio disfrazado de espiritualidad.', 'es', '00bbbb000000000a', '2024-09-29 05:44:32'),
('00bbbb000000000b', 'You want closure from people who are relieved they never have to explain themselves to you.', 'en', NULL, '2024-10-05 13:21:09'),
('00cccc000000000b', 'Buscas cierre en quienes están aliviados de no tener que explicarte nada.', 'es', '00bbbb000000000b', '2024-10-05 13:21:09'),
('00bbbb000000000c', 'The moral high ground has great views and terrible heating.', 'en', NULL, '2024-10-11 20:57:46'),
('00cccc000000000c', 'La moral alta tiene buenas vistas y una calefacción nefasta.', 'es', '00bbbb000000000c', '2024-10-11 20:57:46'),
('00bbbb000000000d', 'You would rather be right in a chat than kind at a dinner table.', 'en', NULL, '2024-10-18 04:34:23'),
('00cccc000000000d', 'Prefieres tener razón en un chat que ser amable en la mesa.', 'es', '00bbbb000000000d', '2024-10-18 04:34:23'),
('00bbbb000000000e', 'Nostalgia is a liar that edits out the parts where you were miserable.', 'en', NULL, '2024-10-24 12:11:00'),
('00cccc000000000e', 'La nostalgia miente: borra los trozos en los que eras infeliz.', 'es', '00bbbb000000000e', '2024-10-24 12:11:00'),
('00bbbb000000000f', 'You think your taste is personality; it is mostly timing and algorithms.', 'en', NULL, '2024-10-30 19:47:37'),
('00cccc000000000f', 'Crees que tu gusto es personalidad; en realidad es timing y algoritmos.', 'es', '00bbbb000000000f', '2024-10-30 19:47:37'),
('00bbbb0000000010', 'People do not forget what you did; they forget what you promised and did not do.', 'en', NULL, '2024-11-06 03:24:14'),
('00cccc0000000010', 'La gente no olvida lo que hiciste; olvida lo que prometiste y no cumpliste.', 'es', '00bbbb0000000010', '2024-11-06 03:24:14'),
('00bbbb0000000011', 'You call it intuition when you are too lazy to trace where the feeling came from.', 'en', NULL, '2024-11-12 11:00:51'),
('00cccc0000000011', 'Le llamas intuición a no querer rastrear de dónde salió el sentimiento.', 'es', '00bbbb0000000011', '2024-11-12 11:00:51'),
('00bbbb0000000012', 'The person you are in traffic is closer to the truth than your dating profile.', 'en', NULL, '2024-11-18 18:37:28'),
('00cccc0000000012', 'El que eres en el tráfico se parece más a la verdad que tu perfil de citas.', 'es', '00bbbb0000000012', '2024-11-18 18:37:28'),
('00bbbb0000000013', 'You want credit for intentions while only actions count for everyone else.', 'en', NULL, '2024-11-25 02:14:05'),
('00cccc0000000013', 'Quieres mérito por las intenciones; para los demás solo cuentan los hechos.', 'es', '00bbbb0000000013', '2024-11-25 02:14:05'),
('00bbbb0000000014', 'Loyalty often means “I already invested too much to admit this was a mistake.”', 'en', NULL, '2024-12-01 09:50:42'),
('00cccc0000000014', 'La lealtad a veces es “invertí demasiado como para admitir que esto fue un error”.', 'es', '00bbbb0000000014', '2024-12-01 09:50:42'),
('00bbbb0000000015', 'You scroll past suffering until it has good lighting and a soundtrack.', 'en', NULL, '2024-12-07 17:27:19'),
('00cccc0000000015', 'Pasas el sufrimiento hasta que tenga buena luz y banda sonora.', 'es', '00bbbb0000000015', '2024-12-07 17:27:19'),
('00bbbb0000000016', 'The kindest lie is still training someone to trust the wrong thing.', 'en', NULL, '2024-12-14 01:03:56'),
('00cccc0000000016', 'La mentira más amable sigue enseñando a confiar en lo equivocado.', 'es', '00bbbb0000000016', '2024-12-14 01:03:56'),
('00bbbb0000000017', 'You mistake being understood for being loved.', 'en', NULL, '2024-12-20 08:40:33'),
('00cccc0000000017', 'Confundes que te entiendan con que te quieran.', 'es', '00bbbb0000000017', '2024-12-20 08:40:33'),
('00bbbb0000000018', 'Your “strong opinions loosely held” are often just regular opinions with a nicer slogan.', 'en', NULL, '2024-12-26 16:17:10'),
('00cccc0000000018', 'Tus “opiniones fuertes, débilmente sujetas” suelen ser opiniones normales con mejor eslogan.', 'es', '00bbbb0000000018', '2024-12-26 16:17:10'),
('00bbbb0000000019', 'You do not fear failure; you fear looking like someone who tried.', 'en', NULL, '2025-01-01 23:53:47'),
('00cccc0000000019', 'No temes fallar; temes parecer alguien que lo intentó.', 'es', '00bbbb0000000019', '2025-01-01 23:53:47'),
('00bbbb000000001a', 'The apology you rehearse in the shower is for your ego, not for them.', 'en', NULL, '2025-01-08 07:30:24'),
('00cccc000000001a', 'La disculpa que ensayas en la ducha es para tu ego, no para ellos.', 'es', '00bbbb000000001a', '2025-01-08 07:30:24'),
('00bbbb000000001b', 'You think you would have been brave in history; you mute relatives at Thanksgiving.', 'en', NULL, '2025-01-14 15:07:01'),
('00cccc000000001b', 'Crees que en el pasado habrías sido valiente; silencias a familiares en Acción de Gracias.', 'es', '00bbbb000000001b', '2025-01-14 15:07:01'),
('00bbbb000000001c', 'Comfort is a drug; the withdrawal is called “growth” on Instagram.', 'en', NULL, '2025-01-20 22:43:38'),
('00cccc000000001c', 'El confort es droga; la abstinencia aquí la llaman “crecimiento” en Instagram.', 'es', '00bbbb000000001c', '2025-01-20 22:43:38'),
('00bbbb000000001d', 'You confuse peace with winning an argument without speaking.', 'en', NULL, '2025-01-27 06:20:15'),
('00cccc000000001d', 'Confundes la paz con ganar la discusión sin abrir la boca.', 'es', '00bbbb000000001d', '2025-01-27 06:20:15'),
('00bbbb000000001e', 'Everyone is the hero until the bill arrives.', 'en', NULL, '2025-02-02 13:56:52'),
('00cccc000000001e', 'Todos son el héroe hasta que llega la cuenta.', 'es', '00bbbb000000001e', '2025-02-02 13:56:52'),
('00bbbb000000001f', 'You want honesty until it includes the part about you.', 'en', NULL, '2025-02-08 21:33:29'),
('00cccc000000001f', 'Quieres honestidad hasta que incluya la parte que te toca.', 'es', '00bbbb000000001f', '2025-02-08 21:33:29'),
('00bbbb0000000020', 'The cruelest mirror is someone who used to adore you being polite.', 'en', NULL, '2025-02-15 05:10:06'),
('00cccc0000000020', 'El espejo más cruel es quien te adoraba y ahora solo es educado.', 'es', '00bbbb0000000020', '2025-02-15 05:10:06'),
('00bbbb0000000021', 'You call it standards; sometimes it is just fear in a blazer.', 'en', NULL, '2025-02-21 12:46:43'),
('00cccc0000000021', 'Le llamas estándares; a veces es miedo con blazer.', 'es', '00bbbb0000000021', '2025-02-21 12:46:43'),
('00bbbb0000000022', 'You remember the one insult and forget ten genuine compliments.', 'en', NULL, '2025-02-27 20:23:19'),
('00cccc0000000022', 'Recuerdas un insulto y olvidas diez halagos sinceros.', 'es', '00bbbb0000000022', '2025-02-27 20:23:19'),
('00bbbb0000000023', 'Being “bad at texting” is often being bad at prioritizing you.', 'en', NULL, '2025-03-06 03:59:56'),
('00cccc0000000023', 'Ser “malo con los mensajes” suele ser malo priorizándote a ti.', 'es', '00bbbb0000000023', '2025-03-06 03:59:56'),
('00bbbb0000000024', 'You think you hate small talk; you hate feeling unseen in big talk too.', 'en', NULL, '2025-03-12 11:36:33'),
('00cccc0000000024', 'Crees que odias la charla trivial; también te sientes invisible en la profunda.', 'es', '00bbbb0000000024', '2025-03-12 11:36:33'),
('00bbbb0000000025', 'The internet did not make you cynical; it removed the plausible deniability.', 'en', NULL, '2025-03-18 19:13:10'),
('00cccc0000000025', 'Internet no te volvió cínico; te quitó la denegación plausible.', 'es', '00bbbb0000000025', '2025-03-18 19:13:10'),
('00bbbb0000000026', 'You want friends who challenge you unless they start with you.', 'en', NULL, '2025-03-25 02:49:47'),
('00cccc0000000026', 'Quieres amigos que te desafíen, salvo cuando el desafío eres tú.', 'es', '00bbbb0000000026', '2025-03-25 02:49:47'),
('00bbbb0000000027', 'Most self-care is marketing for loneliness with a face mask.', 'en', NULL, '2025-03-31 10:26:24'),
('00cccc0000000027', 'Mucho autocuidado es marketing de la soledad con mascarilla.', 'es', '00bbbb0000000027', '2025-03-31 10:26:24'),
('00bbbb0000000028', 'You confuse chemistry with chaos and call it passion.', 'en', NULL, '2025-04-06 18:03:01'),
('00cccc0000000028', 'Confundes la química con el caos y le llamas pasión.', 'es', '00bbbb0000000028', '2025-04-06 18:03:01'),
('00bbbb0000000029', 'The silent treatment works because it confirms you still matter enough to punish.', 'en', NULL, '2025-04-13 01:39:38'),
('00cccc0000000029', 'El trato silencioso funciona porque confirma que aún importas lo bastante para castigar.', 'es', '00bbbb0000000029', '2025-04-13 01:39:38'),
('00bbbb000000002a', 'You do not need closure; you need a version of the story where you are not the villain.', 'en', NULL, '2025-04-19 09:16:15'),
('00cccc000000002a', 'No necesitas cierre; necesitas una versión en la que no seas el villano.', 'es', '00bbbb000000002a', '2025-04-19 09:16:15'),
('00bbbb000000002b', 'Your “toxic ex” story is true and still missing two scenes.', 'en', NULL, '2025-04-25 16:52:52'),
('00cccc000000002b', 'Tu historia del “ex tóxico” es verdad y aún faltan dos escenas.', 'es', '00bbbb000000002b', '2025-04-25 16:52:52'),
('00bbbb000000002c', 'You think you are picky; you are scared and calling it taste.', 'en', NULL, '2025-05-02 00:29:29'),
('00cccc000000002c', 'Crees que eres exigente; tienes miedo y le llamas gusto.', 'es', '00bbbb000000002c', '2025-05-02 00:29:29'),
('00bbbb000000002d', 'The compliment you fish for never fills the hole.', 'en', NULL, '2025-05-08 08:06:06'),
('00cccc000000002d', 'El halago que pescas nunca llena el agujero.', 'es', '00bbbb000000002d', '2025-05-08 08:06:06'),
('00bbbb000000002e', 'You mistake availability for loyalty.', 'en', NULL, '2025-05-14 15:42:43'),
('00cccc000000002e', 'Confundes disponibilidad con lealtad.', 'es', '00bbbb000000002e', '2025-05-14 15:42:43'),
('00bbbb000000002f', 'Everyone agrees mental health matters until someone needs a real accommodation.', 'en', NULL, '2025-05-20 23:19:20'),
('00cccc000000002f', 'Todos dicen que la salud mental importa hasta que hace falta acomodar de verdad.', 'es', '00bbbb000000002f', '2025-05-20 23:19:20'),
('00bbbb0000000030', 'You want to be known deeply without handing over the boring parts.', 'en', NULL, '2025-05-27 06:55:57'),
('00cccc0000000030', 'Quieres que te conozcan en profundidad sin entregar las partes aburridas.', 'es', '00bbbb0000000030', '2025-05-27 06:55:57'),
('00bbbb0000000031', 'The bar for “good person” drops sharply when the person is you.', 'en', NULL, '2025-06-02 14:32:34'),
('00cccc0000000031', 'El listón de “buena persona” baja mucho cuando la persona eres tú.', 'es', '00bbbb0000000031', '2025-06-02 14:32:34'),
('00bbbb0000000032', 'You call it boundaries; sometimes it is just the freeze response with a planner.', 'en', NULL, '2025-06-08 22:09:11'),
('00cccc0000000032', 'Le llamas límites; a veces es congelación con agenda.', 'es', '00bbbb0000000032', '2025-06-08 22:09:11'),
('00bbbb0000000033', 'You will never know how many people decided quietly not to trust you again.', 'en', NULL, '2025-06-15 05:45:48'),
('00cccc0000000033', 'Nunca sabrás cuánta gente decidió, en silencio, no volver a confiar en ti.', 'es', '00bbbb0000000033', '2025-06-15 05:45:48'),
('00dddd0000000001', 'Decís que no te importa el dinero hasta que alguien sugiere pagar mitad y mitad.', 'es', NULL, '2025-06-21 13:22:25'),
('00eeee0000000001', 'You say money does not matter until someone suggests splitting the bill evenly.', 'en', '00dddd0000000001', '2025-06-21 13:22:25'),
('00dddd0000000002', 'El “solo quiero lo mejor para vos” a veces es solo control con buena iluminación.', 'es', NULL, '2025-06-27 20:59:02'),
('00eeee0000000002', '“I only want what is best for you” is sometimes just control with good lighting.', 'en', '00dddd0000000002', '2025-06-27 20:59:02'),
('00dddd0000000003', 'La mayoría de debates en internet no buscan la verdad; buscan un público.', 'es', NULL, '2025-07-04 04:35:39'),
('00eeee0000000003', 'Most online arguments are not after truth; they are after an audience.', 'en', '00dddd0000000003', '2025-07-04 04:35:39'),
('00dddd0000000004', 'Perdonás rápido lo que te conviene olvidar.', 'es', NULL, '2025-07-10 12:12:16'),
('00eeee0000000004', 'You forgive quickly what it is convenient for you to forget.', 'en', '00dddd0000000004', '2025-07-10 12:12:16'),
('00dddd0000000005', 'El silencio en el ascensor es un tratado de paz colectivo que nadie firmó.', 'es', NULL, '2025-07-16 19:48:53'),
('00eeee0000000005', 'Elevator silence is a peace treaty nobody signed.', 'en', '00dddd0000000005', '2025-07-16 19:48:53'),
('00dddd0000000006', 'Te dolés del mundo y después evitás sentarte al lado del que huele mal en el colectivo.', 'es', NULL, '2025-07-23 03:25:30'),
('00eeee0000000006', 'You ache for the world, then avoid sitting next to someone who smells on the bus.', 'en', '00dddd0000000006', '2025-07-23 03:25:30'),
('00dddd0000000007', 'La familia es sagrada hasta que toca terapia y límites.', 'es', NULL, '2025-07-29 11:02:07'),
('00eeee0000000007', 'Family is sacred until therapy and boundaries come up.', 'en', '00dddd0000000007', '2025-07-29 11:02:07'),
('00dddd0000000008', 'Decís que valorás el tiempo ajeno y llegás cinco minutos tarde siempre.', 'es', NULL, '2025-08-04 18:38:44'),
('00eeee0000000008', 'You say you respect people’s time; you are always five minutes late.', 'en', '00dddd0000000008', '2025-08-04 18:38:44'),
('00dddd0000000009', 'El amor propio de Instagram a veces es solo marketing para no pedir ayuda.', 'es', NULL, '2025-08-11 02:15:21'),
('00eeee0000000009', 'Instagram self-love is sometimes marketing for not asking for help.', 'en', '00dddd0000000009', '2025-08-11 02:15:21'),
('00dddd000000000a', 'Te creés desinteresado hasta que no te aplauden lo que regalaste.', 'es', NULL, '2025-08-17 09:51:58'),
('00eeee000000000a', 'You think you are selfless until nobody applauds what you gave.', 'en', '00dddd000000000a', '2025-08-17 09:51:58'),
('00dddd000000000b', 'La envidia se disfraza de “qué suerte tiene”.', 'es', NULL, '2025-08-23 17:28:35'),
('00eeee000000000b', 'Envy dresses up as “they are so lucky.”', 'en', '00dddd000000000b', '2025-08-23 17:28:35'),
('00dddd000000000c', 'Decís que no competís y medís likes en secreto.', 'es', NULL, '2025-08-30 01:05:12'),
('00eeee000000000c', 'You say you are not competing; you secretly count likes.', 'en', '00dddd000000000c', '2025-08-30 01:05:12'),
('00dddd000000000d', 'El “no pasa nada” muchas veces pasa mucho.', 'es', NULL, '2025-09-05 08:41:49'),
('00eeee000000000d', '“It is fine” often means a lot is not fine.', 'en', '00dddd000000000d', '2025-09-05 08:41:49'),
('00dddd000000000e', 'Te gusta la honestidad brutal salvo cuando apunta a tu ego.', 'es', NULL, '2025-09-11 16:18:26'),
('00eeee000000000e', 'You like brutal honesty until it points at your ego.', 'en', '00dddd000000000e', '2025-09-11 16:18:26'),
('00dddd000000000f', 'Prometés cambiar mañana porque hoy ya está gastado el cupo de esfuerzo.', 'es', NULL, '2025-09-17 23:55:02'),
('00eeee000000000f', 'You promise to change tomorrow because today’s effort quota is already spent.', 'en', '00dddd000000000f', '2025-09-17 23:55:02'),
('00dddd0000000010', 'La culpa te hace sentir moral sin obligarte a reparar nada.', 'es', NULL, '2025-09-24 07:31:39'),
('00eeee0000000010', 'Guilt makes you feel moral without forcing you to repair anything.', 'en', '00dddd0000000010', '2025-09-24 07:31:39'),
('00dddd0000000011', 'Decís que no te define el trabajo y te ofendés si no preguntan qué hacés.', 'es', NULL, '2025-09-30 15:08:16'),
('00eeee0000000011', 'You say your job does not define you; you are offended when nobody asks what you do.', 'en', '00dddd0000000011', '2025-09-30 15:08:16'),
('00dddd0000000012', 'El “yo también pasé por eso” a veces roba el micrófono del dolor ajeno.', 'es', NULL, '2025-10-06 22:44:53'),
('00eeee0000000012', '“I went through that too” sometimes steals the mic from someone else’s pain.', 'en', '00dddd0000000012', '2025-10-06 22:44:53'),
('00dddd0000000013', 'Te creés paciente hasta que el Wi‑Fi tarda dos segundos más.', 'es', NULL, '2025-10-13 06:21:30'),
('00eeee0000000013', 'You think you are patient until the Wi‑Fi takes two extra seconds.', 'en', '00dddd0000000013', '2025-10-13 06:21:30'),
('00dddd0000000014', 'La modestia falsa es otra forma de decir “mirame”.', 'es', NULL, '2025-10-19 13:58:07'),
('00eeee0000000014', 'False modesty is another way of saying “look at me.”', 'en', '00dddd0000000014', '2025-10-19 13:58:07'),
('00dddd0000000015', 'Decís que no te importa la ropa y juzgás el outfit del vecino.', 'es', NULL, '2025-10-25 21:34:44'),
('00eeee0000000015', 'You say you do not care about clothes; you judge the neighbor’s outfit.', 'en', '00dddd0000000015', '2025-10-25 21:34:44'),
('00dddd0000000016', 'El “sin drama” suele anunciar drama premium.', 'es', NULL, '2025-11-01 05:11:21'),
('00eeee0000000016', '“No drama” usually announces premium drama.', 'en', '00dddd0000000016', '2025-11-01 05:11:21'),
('00dddd0000000017', 'Te gusta la gente auténtica que coincida con vos en todo.', 'es', NULL, '2025-11-07 12:47:58'),
('00eeee0000000017', 'You like “authentic” people who agree with you on everything.', 'en', '00dddd0000000017', '2025-11-07 12:47:58'),
('00dddd0000000018', 'La nostalgia de la infancia olvida el miedo de entonces.', 'es', NULL, '2025-11-13 20:24:35'),
('00eeee0000000018', 'Childhood nostalgia forgets the fear you felt then.', 'en', '00dddd0000000018', '2025-11-13 20:24:35'),
('00dddd0000000019', 'Decís que no necesitás aprobación y borrás el post con pocos favs.', 'es', NULL, '2025-11-20 04:01:12'),
('00eeee0000000019', 'You say you do not need approval; you delete the post with few favorites.', 'en', '00dddd0000000019', '2025-11-20 04:01:12'),
('00dddd000000001a', 'El “lo digo por tu bien” a veces es por el bien del que lo dice.', 'es', NULL, '2025-11-26 11:37:49'),
('00eeee000000001a', '“I am saying this for your good” is sometimes for the speaker’s good.', 'en', '00dddd000000001a', '2025-11-26 11:37:49'),
('00dddd000000001b', 'Te creés abierto de mente hasta que tocan tu tabú favorito.', 'es', NULL, '2025-12-02 19:14:26'),
('00eeee000000001b', 'You think you are open-minded until someone hits your favorite taboo.', 'en', '00dddd000000001b', '2025-12-02 19:14:26'),
('00dddd000000001c', 'La paz interior muchas veces es evitación con incienso.', 'es', NULL, '2025-12-09 02:51:03'),
('00eeee000000001c', 'Inner peace is often avoidance with incense.', 'en', '00dddd000000001c', '2025-12-09 02:51:03'),
('00dddd000000001d', 'Decís que el tamaño no importa y comparás sueldos en silencio.', 'es', NULL, '2025-12-15 10:27:40'),
('00eeee000000001d', 'You say size does not matter; you silently compare salaries.', 'en', '00dddd000000001d', '2025-12-15 10:27:40'),
('00dddd000000001e', 'El “no soy celoso” vigila historias como un analista de inteligencia.', 'es', NULL, '2025-12-21 18:04:17'),
('00eeee000000001e', '“I am not jealous” watches stories like an intelligence analyst.', 'en', '00dddd000000001e', '2025-12-21 18:04:17'),
('00dddd000000001f', 'Te gusta el debate sano que termina con vos teniendo razón.', 'es', NULL, '2025-12-28 01:40:54'),
('00eeee000000001f', 'You like “healthy debate” that ends with you being right.', 'en', '00dddd000000001f', '2025-12-28 01:40:54'),
('00dddd0000000020', 'La empatía selectiva es la más cómoda.', 'es', NULL, '2026-01-03 09:17:31'),
('00eeee0000000020', 'Selective empathy is the most comfortable kind.', 'en', '00dddd0000000020', '2026-01-03 09:17:31'),
('00dddd0000000021', 'Decís que no te afectan los comentarios y los releés a las 3 a.m.', 'es', NULL, '2026-01-09 16:54:08'),
('00eeee0000000021', 'You say comments do not get to you; you reread them at 3 a.m.', 'en', '00dddd0000000021', '2026-01-09 16:54:08'),
